import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { Empresa } from '@/models/empresa';
import { PaginationMetaData } from '@/models/paginacion';
import { Presale } from '@/models/presunto';
import { User } from '@/models/user';
import { Vendedor } from '@/models/vendedor';
import { url, getCompanyGlobalData } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'presaleList',
    template: () => import('./presale-list.html?raw'),
    data: () => ({
        user: null as User | null,
        empresa: null as Empresa | null,
        nav: null as string | null,
        aside: null as string | null,
        loading: true,
        presales: null as Presale[] | null,
        vendedores: null as Vendedor[] | null,

        paginationMetaData: null as PaginationMetaData | null,
        entriesPerPage: 10,
        entriesStorageKey: 'isiparts.presale.entries-per-page',
        pageInfo: '',

        columnSortKey: 'pre',
        sortOrder: 'desc',

        currentPage: 1,

        currentTab: 0,

        vendedorName(ven: number): string {
            const vendedor = this.vendedores?.find((v: Vendedor) => v.ven === ven);
            return vendedor?.raz || '';
        },

        async init() {
            console.log('presaleList@init');

            try {
                this.user = await getAuthenticatedUser();
                this.empresa = await getCompanyGlobalData(this.user.empOmi);
            } catch (error) {
                location.href = '/login?redirect=/presunto/modify';
            }

            this.nav = await render(nav);
            this.aside = await render(aside);

            this.loading = false;

            this.entriesPerPage = localStorage.getItem(this.entriesStorageKey) ?? 10;

            await Promise.all([this.loadPresales(), this.loadVendedores()]);
        },

        async loadPresales() {
            this.loading = true;
            const baseUrl = `isiWeb/web/v1/empresas/01/presuntos?page=${this.currentPage}&pageSize=${this.entriesPerPage}&sort=${this.columnSortKey}&order=${this.sortOrder}`;
            let fetchUrl = '';
            switch (this.currentTab) {
                case 0:
                    fetchUrl = `${baseUrl}&conf:ne=false`;
                    break;
                case 1:
                    fetchUrl = `${baseUrl}&conf:ne=false&conf:ne=true`;
                    break;
                case 2:
                    fetchUrl = `${baseUrl}&conf:eq=true`;
                    break;
            }
            try {
                const r = await fetch(url(fetchUrl), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                if (!r.ok) {
                    throw new Error('Error loading presales');
                }

                const response = await r.json();
                this.presales = response.data as Presale[];
                this.paginationMetaData = response.meta as PaginationMetaData;

                const startEntry = (this.currentPage - 1) * this.entriesPerPage + 1;
                const endEntry = Math.min(this.currentPage * this.entriesPerPage, this.paginationMetaData.totalRows);
                this.pageInfo = `Mostrando ${startEntry} a ${endEntry} de ${this.paginationMetaData.totalRows} registros`;
            } catch (error: any) {
                console.error(error);
            }
            this.loading = false;
        },

        async sortPresales(columnKey: string) {
            this.columnSortKey = columnKey;
            this.sortOrder = this.sortOrder === 'asc' ? 'desc' : 'asc';
            await this.loadPresales();
        },

        async changeTab() {
            this.currentPage = 1;
            await this.loadPresales();
        },

        async changeEntriesPerPage() {
            this.currentPage = 1;
            localStorage.setItem(this.entriesStorageKey, this.entriesPerPage);
            await this.loadPresales();
        },

        async nextPage() {
            this.currentPage++;
            await this.loadPresales();
        },

        async prevPage() {
            this.currentPage--;
            await this.loadPresales();
        },

        async loadVendedores() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/vendedores'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                if (!r.ok) {
                    throw new Error('Error loading presale vendedor');
                }

                const response = await r.json();
                this.vendedores = response.data as Vendedor[];
            } catch (error: any) {
                console.error(error);
            }
        },
    }),
} as ComponentModule;
